import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';

function MyVideosPage() {
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [deletingId, setDeletingId] = useState(null);
  const [currentUser, setCurrentUser] = useState(null);
  const navigate = useNavigate();

  const getCurrentUser = () => {
    let username = localStorage.getItem('username');
    if (username) return username;
    
    const token = localStorage.getItem('access');
    if (token) {
      try {
        const payload = JSON.parse(atob(token.split('.')[1]));
        username = payload.username;
        if (username) localStorage.setItem('username', username);
        return username;
      } catch (e) {
        return null;
      }
    }
    return null;
  };

  useEffect(() => {
    const token = localStorage.getItem('access');
    if (!token) {
      navigate('/login');
      return;
    }
    
    const user = getCurrentUser();
    setCurrentUser(user);
    fetchVideos(user);
  }, [navigate]);

  const fetchVideos = async (user) => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get('http://localhost:8000/api/videos/', {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      
      const userVideos = response.data.filter(video => video.uploaded_by_name === user);
      setVideos(userVideos);
      setLoading(false);
    } catch (error) {
      console.error('Ошибка загрузки:', error);
      setLoading(false);
    }
  };

  const handleDelete = async (videoId) => {
    if (!window.confirm('Вы уверены, что хотите удалить это видео?')) return;
    
    setDeletingId(videoId);
    try {
      const token = localStorage.getItem('access');
      await axios.delete(`http://localhost:8000/api/videos/${videoId}/`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      
      setVideos(videos.filter(v => v.id !== videoId));
      alert('✅ Видео удалено');
    } catch (error) {
      alert('❌ Не удалось удалить видео');
    } finally {
      setDeletingId(null);
    }
  };

  if (loading) {
    return (
      <div className="fade-in" style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '60vh' }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: 48, marginBottom: 20 }}>📼</div>
          <p style={{ color: 'var(--text-secondary)' }}>Загрузка...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="fade-in" style={{ maxWidth: 1000, margin: '0 auto' }}>
      <div style={{ marginBottom: 32 }}>
        <h1 style={{ fontSize: 32, fontWeight: 700, marginBottom: 8 }}>📼 Мои видео</h1>
        <p style={{ color: 'var(--text-secondary)' }}>
          Вы вошли как <span style={{ color: 'var(--accent)', fontWeight: 500 }}>{currentUser}</span>
        </p>
      </div>
      
      {videos.length === 0 ? (
        <div style={{
          textAlign: 'center',
          padding: 80,
          backgroundColor: 'var(--bg-secondary)',
          borderRadius: 24,
          border: '1px solid var(--border)'
        }}>
          <div style={{ fontSize: 64, marginBottom: 20 }}>📭</div>
          <p style={{ fontSize: 18, color: 'var(--text-secondary)', marginBottom: 24 }}>У вас пока нет загруженных видео</p>
          <Link to="/upload" style={{
            backgroundColor: 'var(--accent)',
            color: 'white',
            padding: '12px 24px',
            borderRadius: 24,
            textDecoration: 'none',
            fontWeight: 500,
            transition: 'var(--transition)'
          }}>
            + Загрузить видео
          </Link>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          {videos.map(video => (
            <div key={video.id} style={{
              backgroundColor: 'var(--bg-card)',
              borderRadius: 16,
              padding: 20,
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              flexWrap: 'wrap',
              gap: 16,
              transition: 'var(--transition)'
            }}>
              <div style={{ flex: 1 }}>
                <Link to={`/video/${video.id}`} style={{ textDecoration: 'none' }}>
                  <h3 style={{ color: 'var(--text-primary)', marginBottom: 8, fontSize: 18 }}>{video.title}</h3>
                </Link>
                <div style={{ display: 'flex', gap: 16, color: 'var(--text-secondary)', fontSize: 13 }}>
                  <span>👁️ {video.views || 0} просмотров</span>
                  <span>📅 {new Date(video.created_at).toLocaleDateString()}</span>
                </div>
                {video.description && (
                  <p style={{ color: 'var(--text-secondary)', fontSize: 14, marginTop: 12 }}>
                    {video.description.length > 100 ? video.description.slice(0, 100) + '...' : video.description}
                  </p>
                )}
              </div>
              
              <button
                onClick={() => handleDelete(video.id)}
                disabled={deletingId === video.id}
                style={{
                  backgroundColor: 'rgba(255,0,0,0.1)',
                  color: 'var(--accent)',
                  border: '1px solid var(--accent)',
                  padding: '10px 20px',
                  borderRadius: 12,
                  cursor: deletingId === video.id ? 'not-allowed' : 'pointer',
                  fontSize: 14,
                  fontWeight: 500,
                  transition: 'var(--transition)'
                }}
                onMouseEnter={(e) => {
                  e.target.style.backgroundColor = 'var(--accent)';
                  e.target.style.color = 'white';
                }}
                onMouseLeave={(e) => {
                  e.target.style.backgroundColor = 'rgba(255,0,0,0.1)';
                  e.target.style.color = 'var(--accent)';
                }}
              >
                {deletingId === video.id ? 'Удаление...' : '🗑️ Удалить'}
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default MyVideosPage;
